import{_ as a,o as n,c as s,ag as l}from"./chunks/framework.DAvaMl8U.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),i={name:"architecture.md"};function r(o,e,t,c,p,h){return n(),s("div",null,[...e[0]||(e[0]=[l(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Incharj is a modular monolith with one ingestion and search loop:</p><ol><li>Connect to external sources</li><li>Normalize and index content</li><li>Serve ranked search results</li></ol><hr><h2 id="runtime-components" tabindex="-1">Runtime components <a class="header-anchor" href="#runtime-components" aria-label="Permalink to &quot;Runtime components&quot;">​</a></h2><p>Three processes share PostgreSQL and Redis:</p><ul><li>Browser (React SPA)</li><li>API (Fastify)</li><li>Worker (BullMQ)</li></ul><h3 id="data-stores" tabindex="-1">Data stores <a class="header-anchor" href="#data-stores" aria-label="Permalink to &quot;Data stores&quot;">​</a></h3><ul><li>PostgreSQL: tenants, connectors, sync state, documents, chunks</li><li>Redis: queue transport and scheduling</li></ul><hr><h2 id="sync-flow-high-level" tabindex="-1">Sync flow (high-level) <a class="header-anchor" href="#sync-flow-high-level" aria-label="Permalink to &quot;Sync flow (high-level)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dispatch (every 30s)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  \`- enqueue sync-enumerate</span></span>
<span class="line"><span>           |</span></span>
<span class="line"><span>           |- enumerate refs + checkpoint</span></span>
<span class="line"><span>           |- enqueue N sync-document jobs</span></span>
<span class="line"><span>           \`- enqueue sync-finalize</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sync-document (per ref)</span></span>
<span class="line"><span>  |- fetchDocument</span></span>
<span class="line"><span>  |- build canonical envelope</span></span>
<span class="line"><span>  \`- ingestCanonicalDocument</span></span>
<span class="line"><span>       |- normalize</span></span>
<span class="line"><span>       |- chunk</span></span>
<span class="line"><span>       |- index</span></span>
<span class="line"><span>       \`- permissions hook</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sync-finalize</span></span>
<span class="line"><span>  |- wait for docs_processed == docs_enqueued</span></span>
<span class="line"><span>  |- complete sync_jobs row</span></span>
<span class="line"><span>  |- persist checkpoint</span></span>
<span class="line"><span>  \`- update connector state</span></span></code></pre></div><p>Detailed stage behavior is split into core docs:</p><ul><li><a href="/Incharj/core-orchestration">Core: Orchestration</a></li><li><a href="/Incharj/core-connectors">Core: Connectors (Plugin Layer)</a></li><li><a href="/Incharj/core-normalization">Core: Normalization</a></li><li><a href="/Incharj/core-chunking">Core: Chunking</a></li><li><a href="/Incharj/core-indexing">Core: Indexing</a></li><li><a href="/Incharj/core-permissions">Core: Permissions</a></li></ul><hr><h2 id="search-flow-high-level" tabindex="-1">Search flow (high-level) <a class="header-anchor" href="#search-flow-high-level" aria-label="Permalink to &quot;Search flow (high-level)&quot;">​</a></h2><p><code>GET /orgs/:slug/search</code> executes in three tiers:</p><ol><li>Stop-word guard</li><li>Full-text search (GIN and tsvector)</li><li>Fuzzy fallback (trigram similarity)</li></ol><p>For SQL-level details and ranking behavior, see:</p><ul><li><a href="/Incharj/search">Search</a></li></ul><hr><h2 id="multi-tenancy-model" tabindex="-1">Multi-tenancy model <a class="header-anchor" href="#multi-tenancy-model" aria-label="Permalink to &quot;Multi-tenancy model&quot;">​</a></h2><p>All user data is org-scoped.</p><ul><li>API middleware enforces membership and role checks</li><li>SQL queries include org filters</li><li>Roles: owner, admin, member</li></ul><hr><h2 id="canonical-document-model" tabindex="-1">Canonical document model <a class="header-anchor" href="#canonical-document-model" aria-label="Permalink to &quot;Canonical document model&quot;">​</a></h2><p>Ingestion uses one internal envelope (<code>CanonicalDocumentEnvelope</code>) with explicit fields for source identity, content metadata, extraction status, and version markers.</p><p>This envelope is the boundary between connector plugins and core indexing stages.</p>`,28)])])}const m=a(i,[["render",r]]);export{u as __pageData,m as default};
